mapper.select:
SELECT id, order_id, type, status, reward, time_limit, pickup_location, dropoff_location, remarks, creator_user_id, taker_user_id, create_time, update_time
FROM `order`
WHERE order_id = #{orderId}

SELECT id, order_id, type, status, reward, time_limit, pickup_location, dropoff_location, remarks, creator_user_id, taker_user_id, create_time, update_time FROM `order`
AND type = #{type}
ORDER BY reward ASC
ORDER BY reward DESC
ORDER BY create_time DESC
LIMIT #{offset}, #{limit}
